const (
	postAttemptTriagePromptSource = "bead-lifecycle-triage"
	postAttemptTriageSkillName    = "bead-lifecycle"
	maxTriageEventBodyBytes       = 4096
	maxTriageEventCount           = 8
	defaultSessionLogExcerptBytes = 4096
)

// SessionLogExcerptReader reads a bounded excerpt from a session log path.
// The default implementation searches the project agent log dir for a
// matching agent-*.jsonl or svc-*.jsonl file.
type SessionLogExcerptReader interface {
	ReadSessionLogExcerpt(ctx context.Context, projectRoot, sessionID string, maxBytes int) (string, error)
}

type fileSessionLogExcerptReader struct{}

func (fileSessionLogExcerptReader) ReadSessionLogExcerpt(ctx context.Context, projectRoot, sessionID string, maxBytes int) (string, error) {
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return "", err
		}
	}
	path, ok := resolveSessionLogPath(projectRoot, sessionID)
	if !ok {
		return "", os.ErrNotExist
	}
	return readBoundedFileTail(path, maxBytes)
}

type triagePromptBead struct {
	ID           string            `json:"id"`
	Title        string            `json:"title"`
	Status       string            `json:"status,omitempty"`
	Priority     int               `json:"priority,omitempty"`
	IssueType    string            `json:"issue_type,omitempty"`
	Labels       []string          `json:"labels,omitempty"`
	Parent       string            `json:"parent,omitempty"`
	Description  string            `json:"description,omitempty"`
	Acceptance   string            `json:"acceptance,omitempty"`
	Notes        string            `json:"notes,omitempty"`
	Dependencies []bead.Dependency `json:"dependencies,omitempty"`
	Extra        map[string]any    `json:"extra,omitempty"`
}

type triagePromptEnvelope struct {
	Bead           triagePromptBead  `json:"bead"`
	ExecuteBead    ExecuteBeadReport `json:"execute_bead_report"`
	RecentEvents   []bead.BeadEvent  `json:"recent_bead_events,omitempty"`
	SessionExcerpt string            `json:"session_log_excerpt,omitempty"`
	ProjectRoot    string            `json:"project_root,omitempty"`
	SessionLogPath string            `json:"session_log_path,omitempty"`
}

// NewPostAttemptTriageHook constructs the bead-lifecycle post-attempt triage
// hook. The hook is runner-backed, uses the resolved config / runner dispatch
// seam, and never shells out through os/exec.
func NewPostAttemptTriageHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner, sessionLogReader SessionLogExcerptReader) func(ctx context.Context, beadID string, report ExecuteBeadReport) (TriageResult, error) {
	reader := sessionLogReader
	if reader == nil {
		reader = fileSessionLogExcerptReader{}
	}
	return func(ctx context.Context, beadID string, report ExecuteBeadReport) (TriageResult, error) {
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return TriageResult{}, err
			}
		}
		if store == nil {
			return TriageResult{}, fmt.Errorf("triage hook: bead reader required")
		}

		b, err := store.Get(beadID)
		if err != nil {
			return TriageResult{}, fmt.Errorf("triage hook: load bead %s: %w", beadID, err)
		}

		var eventLister interface {
			Events(id string) ([]bead.BeadEvent, error)
		}
		if l, ok := any(store).(interface {
			Events(id string) ([]bead.BeadEvent, error)
		}); ok {
			eventLister = l
		}

		prompt, err := buildPostAttemptTriagePrompt(ctx, projectRoot, b, report, reader, eventLister)
		if err != nil {
			return TriageResult{}, err
		}

		result, err := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, AgentRunRuntime{
			Prompt:       prompt,
			WorkDir:      projectRoot,
			PromptSource: postAttemptTriagePromptSource,
		})
		if err != nil {
			return TriageResult{}, fmt.Errorf("triage hook: dispatch: %w", err)
		}

		payload, err := triageResultPayload(result)
		if err != nil {
			return TriageResult{}, err
		}

		var out TriageResult
		if err := json.Unmarshal([]byte(payload), &out); err != nil {
			return TriageResult{}, fmt.Errorf("triage hook: decode result: %w", err)
		}
		out.Classification = strings.TrimSpace(out.Classification)
		out.RecommendedAction = strings.TrimSpace(out.RecommendedAction)
		out.Rationale = strings.TrimSpace(out.Rationale)
		out.SuggestedAmendments = strings.TrimSpace(out.SuggestedAmendments)
		if out.Classification == "" {
			return TriageResult{}, fmt.Errorf("triage hook: missing classification")
		}
		return out, nil
	}
}

func buildPostAttemptTriagePrompt(ctx context.Context, projectRoot string, b *bead.Bead, report ExecuteBeadReport, reader SessionLogExcerptReader, eventLister interface {
	Events(id string) ([]bead.BeadEvent, error)
}) (string, error) {
	env := triagePromptEnvelope{
		Bead: triagePromptBead{
			ID:           b.ID,
			Title:        strings.TrimSpace(b.Title),
			Status:       strings.TrimSpace(b.Status),
			Priority:     b.Priority,
			IssueType:    strings.TrimSpace(b.IssueType),
			Labels:       append([]string(nil), b.Labels...),
			Parent:       strings.TrimSpace(b.Parent),
			Description:  strings.TrimSpace(b.Description),
			Acceptance:   strings.TrimSpace(b.Acceptance),
			Notes:        strings.TrimSpace(b.Notes),
			Dependencies: append([]bead.Dependency(nil), b.Dependencies...),
		},
		ExecuteBead: report,
		ProjectRoot: projectRoot,
	}
	if len(b.Extra) > 0 {
		env.Bead.Extra = make(map[string]any, len(b.Extra))
		for k, v := range b.Extra {
			if k == "events" || k == "events_attachment" {
				continue
			}
			env.Bead.Extra[k] = v
		}
	}

	if eventLister != nil {
		events, err := eventLister.Events(b.ID)
		if err == nil && len(events) > 0 {
			start := len(events) - maxTriageEventCount
			if start < 0 {
				start = 0
			}
			env.RecentEvents = make([]bead.BeadEvent, 0, len(events)-start)
			for _, ev := range events[start:] {
				env.RecentEvents = append(env.RecentEvents, clampTriageEvent(ev))
			}
		}
	}

	if report.SessionID != "" && reader != nil {
		excerpt, err := reader.ReadSessionLogExcerpt(ctx, projectRoot, report.SessionID, defaultSessionLogExcerptBytes)
		if err == nil && strings.TrimSpace(excerpt) != "" {
			env.SessionExcerpt = excerpt
			if path, ok := resolveSessionLogPath(projectRoot, report.SessionID); ok {
				env.SessionLogPath = path
			}
		}
	}

	body, err := json.MarshalIndent(env, "", "  ")
	if err != nil {
		return "", err
	}

	var sb strings.Builder
	sb.WriteString("MODE: triage\n")
	sb.WriteString("You are the bead-lifecycle skill (" + postAttemptTriageSkillName + "). Classify the outcome of the attempt and return exactly one JSON object.\n")
	sb.WriteString("Return structured JSON with the fields classification, recommended_action, rationale, suggested_amendments, suggested_followup_beads.\n")
	sb.WriteString("Required output shape example: {\"classification\":\"transport\",\"recommended_action\":\"retry\",\"rationale\":\"transient\",\"suggested_amendments\":\"none\",\"suggested_followup_beads\":[]}\n")
	sb.WriteString("Use stable machine-readable classifications such as transport, quota, routing, timeout, merge_conflict, tests_red, needs_decomposition, needs_human, or success.\n")
	sb.WriteString("Do not wrap the answer in markdown or prose.\n\n")
	sb.WriteString("```json\n")
	sb.Write(body)
	sb.WriteString("\n```\n")
	return sb.String(), nil
}

func triageResultPayload(result *Result) (string, error) {
	if result == nil {
		return "", fmt.Errorf("triage hook: empty runner result")
	}
	text := strings.TrimSpace(result.CondensedOutput)
	if text == "" {
		text = strings.TrimSpace(result.Output)
	}
	if text == "" {
		return "", fmt.Errorf("triage hook: empty output")

package agent

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// LintHookErrorKind classifies infra failures returned by the pre-dispatch
// lint hook. The execute loop treats these as fail-open warnings rather than
// quality-policy results.
type LintHookErrorKind string

const (
	LintHookErrorKindMissingSkill    LintHookErrorKind = "missing-skill"
	LintHookErrorKindMissingHarness  LintHookErrorKind = "missing-harness"
	LintHookErrorKindEmptyOutput     LintHookErrorKind = "empty-output"
	LintHookErrorKindBadJSON         LintHookErrorKind = "bad-json"
	LintHookErrorKindCanceled        LintHookErrorKind = "canceled"
	LintHookErrorKindDispatchFailure LintHookErrorKind = "dispatch-failure"
)

// LintHookError is a typed infrastructure error returned by the lint hook.
// The Kind field is stable for errors.Is comparisons; Err carries the wrapped
// cause for logs and diagnostics.
type LintHookError struct {
	Kind LintHookErrorKind
	Err  error
}

func (e *LintHookError) Error() string {
	if e == nil {
		return "<nil>"
	}
	if e.Err == nil {
		return "lint hook: " + string(e.Kind)
	}
	return fmt.Sprintf("lint hook: %s: %v", e.Kind, e.Err)
}

func (e *LintHookError) Unwrap() error {
	if e == nil {
		return nil
	}
	return e.Err
}

func (e *LintHookError) Is(target error) bool {
	t, ok := target.(*LintHookError)
	if !ok || e == nil || t == nil {
		return false
	}
	return e.Kind == t.Kind
}

var (
	ErrLintHookMissingSkill   = &LintHookError{Kind: LintHookErrorKindMissingSkill}
	ErrLintHookMissingHarness = &LintHookError{Kind: LintHookErrorKindMissingHarness}
	ErrLintHookEmptyOutput    = &LintHookError{Kind: LintHookErrorKindEmptyOutput}
	ErrLintHookBadJSON        = &LintHookError{Kind: LintHookErrorKindBadJSON}
	ErrLintHookCanceled       = &LintHookError{Kind: LintHookErrorKindCanceled}
	ErrLintHookDispatch       = &LintHookError{Kind: LintHookErrorKindDispatchFailure}
)

type lintPromptBead struct {
	ID          string         `json:"id"`
	Title       string         `json:"title"`
	Type        string         `json:"type"`
	Labels      []string       `json:"labels,omitempty"`
	Parent      string         `json:"parent,omitempty"`
	Deps        []string       `json:"deps,omitempty"`
	Description string         `json:"description,omitempty"`
	Acceptance  string         `json:"acceptance,omitempty"`
	Notes       string         `json:"notes,omitempty"`
	Custom      map[string]any `json:"custom_fields,omitempty"`
}

// NewPreDispatchLintHook constructs the bead-lifecycle lint hook used before
// execute-loop dispatch.
func NewPreDispatchLintHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner) func(ctx context.Context, beadID string) (LintResult, error) {
	return func(ctx context.Context, beadID string) (LintResult, error) {
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindCanceled, Err: err}
			}
		}
		if strings.TrimSpace(rcfg.Harness()) == "" {
			return LintResult{}, ErrLintHookMissingHarness
		}
		if !hasBeadLifecycleSkill(projectRoot) {
			return LintResult{}, ErrLintHookMissingSkill
		}
		if store == nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("bead reader required")}
		}

		b, err := store.Get(beadID)
		if err != nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("load bead %s: %w", beadID, err)}
		}

		prompt, err := buildPreDispatchLintPrompt(b)
		if err != nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: err}
		}

		result, err := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, AgentRunRuntime{
			Prompt:       prompt,
			WorkDir:      projectRoot,
			PromptSource: "bead-lifecycle-lint",
		})
		if err != nil {
			switch {
			case errors.Is(err, context.Canceled), errors.Is(err, context.DeadlineExceeded):
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindCanceled, Err: err}
			case isUnknownHarnessError(err):
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindMissingHarness, Err: err}
			case isMissingSkillError(err):
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindMissingSkill, Err: err}
			default:
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: err}
			}
		}

		payload, parseErr := lintResultPayload(result)
		if parseErr != nil {
			return LintResult{}, parseErr
		}
		var out LintResult
		if err := json.Unmarshal([]byte(payload), &out); err != nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindBadJSON, Err: err}
		}
		return out, nil
	}
}

func buildPreDispatchLintPrompt(b *bead.Bead) (string, error) {
	env := lintPromptBead{
		ID:          b.ID,
		Title:       strings.TrimSpace(b.Title),
		Type:        b.IssueType,
		Labels:      append([]string(nil), b.Labels...),
		Parent:      strings.TrimSpace(b.Parent),
		Deps:        append([]string(nil), b.DepIDs()...),
		Description: strings.TrimSpace(b.Description),
		Acceptance:  strings.TrimSpace(b.Acceptance),
		Notes:       strings.TrimSpace(b.Notes),
	}
	if len(b.Extra) > 0 {
		env.Custom = make(map[string]any, len(b.Extra))
		for k, v := range b.Extra {
			env.Custom[k] = v
		}
	}

	body, err := json.MarshalIndent(env, "", "  ")
	if err != nil {
		return "", err
	}

	var sb strings.Builder
	sb.WriteString("MODE: lint\n")
	sb.WriteString("You are the bead-lifecycle skill. Score the bead below using lint mode and return exactly one JSON object matching LintResult.\n")
	sb.WriteString("Return only JSON with these top-level fields.\n")
	sb.WriteString("Required output shape example: {\"score\":0,\"rationale\":\"\",\"suggested_fixes\":[],\"waivers_applied\":[]}\n")
	sb.WriteString("Do not wrap the answer in markdown or prose.\n\n")
	sb.WriteString("```json\n")
	sb.Write(body)
	sb.WriteString("\n```\n")
	return sb.String(), nil
}

func lintResultPayload(result *Result) (string, error) {
	if result == nil {
		return "", &LintHookError{Kind: LintHookErrorKindEmptyOutput, Err: fmt.Errorf("nil result")}
	}
	text := strings.TrimSpace(result.CondensedOutput)
	if text == "" {
		text = strings.TrimSpace(result.Output)
	}
	if text == "" {
		return "", ErrLintHookEmptyOutput
	}
	candidate, ok := extractJSONCandidate(text)
	if !ok {
		return "", &LintHookError{Kind: LintHookErrorKindBadJSON, Err: fmt.Errorf("no JSON object found")}
	}
	return candidate, nil
}

func hasBeadLifecycleSkill(projectRoot string) bool {
	if strings.TrimSpace(projectRoot) == "" {
		return false
	}
	candidates := []string{
		filepath.Join(projectRoot, ".agents", "skills", "ddx", "bead-lifecycle", "SKILL.md"),
		filepath.Join(projectRoot, ".claude", "skills", "ddx", "bead-lifecycle", "SKILL.md"),
	}
	for _, p := range candidates {
		if _, err := os.Stat(p); err == nil {
			return true
		}
	}
	return false
}

func isUnknownHarnessError(err error) bool {
	if err == nil {
		return false
	}
	s := strings.ToLower(err.Error())
	return strings.Contains(s, "unknown harness") || strings.Contains(s, "harness not found")
}

func isMissingSkillError(err error) bool {
	if err == nil {
		return false
	}
	s := strings.ToLower(err.Error())
	return strings.Contains(s, "skill missing") || strings.Contains(s, "bead-lifecycle")
}

