// dispatch.go owns the SD-024 dispatch seam shared by execute-bead and the
// post-merge reviewer. It threads durable knobs from a sealed
// config.ResolvedConfig with per-invocation plumbing/intent from an
// AgentRunRuntime through the same service-or-runner routing used by
// RunWithConfigViaService for `ddx agent run`.

import (
	"context"
	"fmt"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// dispatchViaResolvedConfig is the internal SD-024 dispatch seam shared by
// execute-bead's worker and the post-merge reviewer. It resolves how the
// agent invocation is executed (test-injected runner, pre-built service, or
// a fresh service constructed from projectRoot) and routes through
// executeOnService so every durable knob lands on the dispatched request
// exactly once.
//
// Resolution order:
//  1. runner (test injection seam) — used directly via runner.Run after
//     applying any AgentRunRuntime overrides.
//  2. svc (pre-built service) — used via executeOnService.
//  3. Fallback: construct a fresh service via NewServiceFromWorkDir(projectRoot)
//     and dispatch via executeOnService.
//
// Override fields on runtime (HarnessOverride, ModelOverride,
// PermissionsOverride, SessionLogDirOverride) take precedence over the
// matching rcfg accessors when non-empty, so callers can pin one knob for
// a single invocation without re-resolving the full ResolvedConfig.
func dispatchViaResolvedConfig(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
	if runner != nil {
		return runner.Run(buildRunArgsFromConfig(ctx, rcfg, runtime))
	}
	// DDx-local harnesses (virtual, script) are not upstream service harnesses.
	// Route them through the local Runner so DDX_VIRTUAL_RESPONSES and script
	// directives work correctly via compare and quorum paths, not just agent run.
	harness := runtime.HarnessOverride
	if harness == "" {
		harness = rcfg.Harness()
	}
	if harness == "virtual" || harness == "script" {
		cfg := Config{SessionLogDir: ResolveLogDir(projectRoot, "")}
		r := NewRunner(cfg)
		r.WorkDir = projectRoot
		return r.Run(buildRunArgsFromConfig(ctx, rcfg, runtime))
	}
	if svc == nil {
		factory := serviceRunFactory
		if factory == nil {
			factory = NewServiceFromWorkDir
		}
		built, err := factory(projectRoot)
		if err != nil {
			return nil, fmt.Errorf("agent: build service: %w", err)
		}
		svc = built
	}
	return executeOnService(ctx, svc, projectRoot, rcfg, runtime)
}

// buildRunArgsFromConfig assembles a RunArgs value for the test
// injection runner path. It applies AgentRunRuntime overrides so a caller
// (execute-bead worker, post-merge reviewer) can pin one durable knob for
// a single invocation without re-resolving the full ResolvedConfig.
func buildRunArgsFromConfig(ctx context.Context, rcfg config.ResolvedConfig, runtime AgentRunRuntime) RunArgs {
	harness := runtime.HarnessOverride
	if harness == "" {
		harness = rcfg.Harness()
	}
	model := runtime.ModelOverride
	if model == "" {
		model = rcfg.Model()
	}
	permissions := runtime.PermissionsOverride
	if permissions == "" {
		permissions = rcfg.Permissions()
	}
	sessionLogDir := runtime.SessionLogDirOverride
	if sessionLogDir == "" {
		sessionLogDir = rcfg.SessionLogDir()
	}

	var opts RunArgs
	opts.Context = ctx
	opts.Harness = harness
	// evidence:allow-unbounded reason="caller is responsible for bounding the prompt before invoking dispatchViaResolvedConfig; downstream executeOnService hits readPromptFileBounded for PromptFile inputs"
	opts.Prompt = runtime.Prompt
	opts.PromptFile = runtime.PromptFile
	opts.PromptSource = runtime.PromptSource
	opts.Correlation = runtime.Correlation
	opts.Role = runtime.Role
	opts.CorrelationID = runtime.CorrelationID
	opts.Model = model
	opts.Provider = rcfg.Provider()
	opts.ModelRef = rcfg.ModelRef()
	opts.Effort = rcfg.Effort()
	opts.Timeout = rcfg.Timeout()
	opts.WallClock = rcfg.WallClock()
	opts.WorkDir = runtime.WorkDir
	opts.Permissions = permissions
	opts.SessionLogDir = sessionLogDir
	return opts
}

package agent

import (
	"context"
	"io"
	"path/filepath"
	"time"
)

// Config holds agent service configuration.
type Config struct {
	Profile         string              `yaml:"profile"`          // default routing intent: default, cheap, fast, smart
	Harness         string              `yaml:"harness"`          // optional forced harness override
	Model           string              `yaml:"model"`            // optional default model ref or exact pin
	Models          map[string]string   `yaml:"models"`           // per-harness model overrides
	ReasoningLevels map[string][]string `yaml:"reasoning_levels"` // per-harness reasoning-level options
	TimeoutMS       int                 `yaml:"timeout_ms"`       // idle (inactivity) timeout in ms — resets on every stream/event
	WallClockMS     int                 `yaml:"wall_clock_ms"`    // absolute wall-clock cap in ms — fires regardless of activity
	SessionLogDir   string              `yaml:"session_log_dir"`  // log directory
	Permissions     string              `yaml:"permissions"`      // permission level: safe, supervised, unrestricted
}

// RouteFlags holds raw CLI flag values before normalization into a RouteRequest.
// These come directly from parsed command-line arguments.
type RouteFlags struct {
	Profile     string // --profile: default, cheap, fast, smart
	Model       string // --model: logical ref or exact pin
	Provider    string // --provider: explicit provider name
	ModelRef    string // --model-ref: catalog model reference
	Harness     string // --harness: forced harness override
	Effort      string // --effort: low, medium, high
	Permissions string // --permissions: safe, supervised, unrestricted
}

// RunArgs holds options for a single agent invocation.
type RunArgs struct {
	// Context is the caller's context. When non-nil, the Runner derives its
	// internal cancel context from this so upstream cancellation (e.g.
	// server.WorkerManager.Stop) propagates into the provider HTTP call.
	// Nil defaults to context.Background().
	Context       context.Context
	Harness       string
	Prompt        string // prompt text (or path to file)
	PromptFile    string // explicit file path
	PromptSource  string
	Correlation   map[string]string
	Model         string
	Provider      string // explicit provider name (e.g. "vidar", "openrouter"); bypasses default provider selection
	ModelRef      string // catalog model-ref (e.g. "code-medium"); resolved via the model catalog
	Effort        string
	Timeout       time.Duration // idle (inactivity) timeout; nonzero overrides Config.TimeoutMS
	WallClock     time.Duration // absolute wall-clock cap; nonzero overrides Config.WallClockMS
	WorkDir       string
	Permissions   string // permission level override: safe, supervised, unrestricted
	SessionLogDir string // per-run override for session log dir; used by execute-bead to redirect embedded-agent runtime state out of the worktree root
	Role          string
	CorrelationID string
}

// AgentRunRuntime is the SD-024 successor to RunArgs for the agent
// run path. Durable knobs (Harness, Model, Provider, ModelRef, Effort,
// Permissions, Timeout, WallClock, SessionLogDir) are stripped — they
// live on config.ResolvedConfig and are passed via RunWithConfig's
// rcfg argument. Only non-serializable plumbing and per-invocation
// runtime intent remain.
//
// See SD-024 / TD-024 §Runtime structs and §Stage 2 bead 17.
type AgentRunRuntime struct {
	Prompt                string
	PromptFile            string
	PromptSource          string
	Output                io.Writer
	Correlation           map[string]string
	Record                bool
	Replay                bool
	WorkDir               string
	EstimatedPromptTokens int
	RequiresTools         bool
	SessionLogDirOverride string
	// HarnessOverride, ModelOverride, and PermissionsOverride let a caller
	// pin one of the durable knobs from rcfg for this single invocation
	// without re-resolving the full ResolvedConfig. SD-024 step B22d-d:
	// execute-bead pins permissions=unrestricted; the post-merge reviewer
	// pins harness/model to the reviewer-tier selection.
	HarnessOverride     string
	ModelOverride       string
	PermissionsOverride string
	Role                string
	CorrelationID       string
	// MinPowerOverride, when > 0, overrides rcfg.MinPower() for this single
	// invocation. Used by the post-merge reviewer to pin MinPower above the
	// implementer's actual selected power, biasing routing toward a stronger
	// reviewer model (R4 pairing: reviewer >= impl + 1 power).
	MinPowerOverride int
}

// Result holds the output of an agent invocation.
type Result struct {
	Harness                     string  `json:"harness"`
	Provider                    string  `json:"provider,omitempty"`
	Model                       string  `json:"model,omitempty"`
	ActualPower                 int     `json:"actual_power,omitempty"`
	PredictedPower              int     `json:"predicted_power,omitempty"`
	PredictedSpeedTPS           float64 `json:"predicted_speed_tps,omitempty"`
	PredictedCostUSDPer1kTokens float64 `json:"predicted_cost_usd_per_1k_tokens,omitempty"`
	PredictedCostSource         string  `json:"predicted_cost_source,omitempty"`
	ExitCode                    int     `json:"exit_code"`
	Output                      string  `json:"output"`
	CondensedOutput             string  `json:"condensed_output,omitempty"`
	Stderr                      string  `json:"stderr,omitempty"`
	// Routing evidence populated by the embedded agent harness (RunAgent) or
	// the script harness (RunScript). Used by ExecuteBead to record kind:routing
	// evidence on the bead.
	RouteReason     string          `json:"route_reason,omitempty"`
	ResolvedBaseURL string          `json:"resolved_base_url,omitempty"`
	Tokens          int             `json:"tokens,omitempty"`
	InputTokens     int             `json:"input_tokens,omitempty"`
	CachedTokens    int             `json:"cached_tokens,omitempty"`
	OutputTokens    int             `json:"output_tokens,omitempty"`
	CostUSD         float64         `json:"cost_usd,omitempty"`
	DurationMS      int             `json:"duration_ms"`
	Error           string          `json:"error,omitempty"`
	ToolCalls       []ToolCallEntry `json:"tool_calls,omitempty"`       // populated by agent, nil for subprocess
	AgentSessionID  string          `json:"agent_session_id,omitempty"` // agent session ID for event log cross-reference
}

// SessionEntry is written to the session log.
