 17	// LintHookErrorKind classifies infra failures returned by the pre-dispatch
 18	// lint hook. The execute loop treats these as fail-open warnings rather than
 19	// quality-policy results.
 20	type LintHookErrorKind string
 21	
 22	const (
 23		LintHookErrorKindMissingSkill    LintHookErrorKind = "missing-skill"
 24		LintHookErrorKindMissingHarness  LintHookErrorKind = "missing-harness"
 25		LintHookErrorKindEmptyOutput     LintHookErrorKind = "empty-output"
 26		LintHookErrorKindBadJSON         LintHookErrorKind = "bad-json"
 27		LintHookErrorKindCanceled        LintHookErrorKind = "canceled"
 28		LintHookErrorKindDispatchFailure LintHookErrorKind = "dispatch-failure"
 29	)
 30	
 31	// LintHookError is a typed infrastructure error returned by the lint hook.
 32	// The Kind field is stable for errors.Is comparisons; Err carries the wrapped
 33	// cause for logs and diagnostics.
 34	type LintHookError struct {
 35		Kind LintHookErrorKind
 36		Err  error
 37	}
 38	
 39	func (e *LintHookError) Error() string {
 40		if e == nil {
 41			return "<nil>"
 42		}
 43		if e.Err == nil {
 44			return "lint hook: " + string(e.Kind)
 45		}
 46		return fmt.Sprintf("lint hook: %s: %v", e.Kind, e.Err)
 47	}
 48	
 49	func (e *LintHookError) Unwrap() error {
 50		if e == nil {
 51			return nil
 52		}
 53		return e.Err
 54	}
 55	
 56	func (e *LintHookError) Is(target error) bool {
 57		t, ok := target.(*LintHookError)
 58		if !ok || e == nil || t == nil {
 59			return false
 60		}
 61		return e.Kind == t.Kind
 62	}
 63	
 64	var (
 65		ErrLintHookMissingSkill   = &LintHookError{Kind: LintHookErrorKindMissingSkill}
 66		ErrLintHookMissingHarness = &LintHookError{Kind: LintHookErrorKindMissingHarness}
 67		ErrLintHookEmptyOutput    = &LintHookError{Kind: LintHookErrorKindEmptyOutput}
 68		ErrLintHookBadJSON        = &LintHookError{Kind: LintHookErrorKindBadJSON}
 69		ErrLintHookCanceled       = &LintHookError{Kind: LintHookErrorKindCanceled}
 70		ErrLintHookDispatch       = &LintHookError{Kind: LintHookErrorKindDispatchFailure}
 71	)
