 86	// NewPreDispatchLintHook constructs the bead-lifecycle lint hook used before
 87	// execute-loop dispatch.
 88	func NewPreDispatchLintHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner) func(ctx context.Context, beadID string) (LintResult, error) {
 89		return func(ctx context.Context, beadID string) (LintResult, error) {
 90			if ctx != nil {
 91				if err := ctx.Err(); err != nil {
 92					return LintResult{}, &LintHookError{Kind: LintHookErrorKindCanceled, Err: err}
 93				}
 94			}
 95			if strings.TrimSpace(rcfg.Harness()) == "" {
 96				return LintResult{}, ErrLintHookMissingHarness
 97			}
 98			if !hasBeadLifecycleSkill(projectRoot) {
 99				return LintResult{}, ErrLintHookMissingSkill
100			}
101			if store == nil {
102				return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("bead reader required")}
103			}
104	
105			b, err := store.Get(beadID)
106			if err != nil {
107				return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("load bead %s: %w", beadID, err)}
108			}
109	
110			prompt, err := buildPreDispatchLintPrompt(b)
111			if err != nil {
112				return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: err}
113			}
114	
115			result, err := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, AgentRunRuntime{
116				Prompt:       prompt,
117				WorkDir:      projectRoot,
118				PromptSource: "bead-lifecycle-lint",
119			})
120			if err != nil {
121				switch {
122				case errors.Is(err, context.Canceled), errors.Is(err, context.DeadlineExceeded):
123					return LintResult{}, &LintHookError{Kind: LintHookErrorKindCanceled, Err: err}
124				case isUnknownHarnessError(err):
125					return LintResult{}, &LintHookError{Kind: LintHookErrorKindMissingHarness, Err: err}
126				case isMissingSkillError(err):
127					return LintResult{}, &LintHookError{Kind: LintHookErrorKindMissingSkill, Err: err}
128				default:
129					return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: err}
130				}
131			}
132	
133			payload, parseErr := lintResultPayload(result)
134			if parseErr != nil {
135				return LintResult{}, parseErr
136			}
137			var out LintResult
138			if err := json.Unmarshal([]byte(payload), &out); err != nil {
139				return LintResult{}, &LintHookError{Kind: LintHookErrorKindBadJSON, Err: err}
140			}
141			return out, nil
142		}
143	}
