145	func buildPreDispatchLintPrompt(b *bead.Bead) (string, error) {
146		env := lintPromptBead{
147			ID:          b.ID,
148			Title:       strings.TrimSpace(b.Title),
149			Type:        b.IssueType,
150			Labels:      append([]string(nil), b.Labels...),
151			Parent:      strings.TrimSpace(b.Parent),
152			Deps:        append([]string(nil), b.DepIDs()...),
153			Description: strings.TrimSpace(b.Description),
154			Acceptance:  strings.TrimSpace(b.Acceptance),
155			Notes:       strings.TrimSpace(b.Notes),
156		}
157		if len(b.Extra) > 0 {
158			env.Custom = make(map[string]any, len(b.Extra))
159			for k, v := range b.Extra {
160				env.Custom[k] = v
161			}
162		}
163	
164		body, err := json.MarshalIndent(env, "", "  ")
165		if err != nil {
166			return "", err
167		}
168	
169		var sb strings.Builder
170		sb.WriteString("MODE: lint\n")
171		sb.WriteString("You are the bead-lifecycle skill. Score the bead below using lint mode and return exactly one JSON object matching LintResult.\n")
172		sb.WriteString("Return only JSON with these top-level fields.\n")
173		sb.WriteString("Required output shape example: {\"score\":0,\"rationale\":\"\",\"suggested_fixes\":[],\"waivers_applied\":[]}\n")
174		sb.WriteString("Do not wrap the answer in markdown or prose.\n\n")
175		sb.WriteString("```json\n")
176		sb.Write(body)
177		sb.WriteString("\n```\n")
178		return sb.String(), nil
179	}
