181	func lintResultPayload(result *Result) (string, error) {
182		if result == nil {
183			return "", &LintHookError{Kind: LintHookErrorKindEmptyOutput, Err: fmt.Errorf("nil result")}
184		}
185		text := strings.TrimSpace(result.CondensedOutput)
186		if text == "" {
187			text = strings.TrimSpace(result.Output)
188		}
189		if text == "" {
190			return "", ErrLintHookEmptyOutput
191		}
192		candidate, ok := extractJSONCandidate(text)
193		if !ok {
194			return "", &LintHookError{Kind: LintHookErrorKindBadJSON, Err: fmt.Errorf("no JSON object found")}
195		}
196		return candidate, nil
197	}
