199	func hasBeadLifecycleSkill(projectRoot string) bool {
200		if strings.TrimSpace(projectRoot) == "" {
201			return false
202		}
203		candidates := []string{
204			filepath.Join(projectRoot, ".agents", "skills", "ddx", "bead-lifecycle", "SKILL.md"),
205			filepath.Join(projectRoot, ".claude", "skills", "ddx", "bead-lifecycle", "SKILL.md"),
206		}
207		for _, p := range candidates {
208			if _, err := os.Stat(p); err == nil {
209				return true
210			}
211		}
212		return false
213	}
